const input = $input.first().json;
const body = input.body ?? input;
const question = typeof body.question === 'string' && body.question.trim() ? body.question.trim() : 'What should I know from the current wiki state?';
const limit = Number.isFinite(Number(body.limit)) && Number(body.limit) > 0 ? Number(body.limit) : 8;
return [{ json: { question, limit } }];

const stdout = $input.first().json.stdout ?? '';
if (!stdout.trim()) {
  throw new Error('search.ts returned empty stdout');
}
return [{ json: JSON.parse(stdout) }];

const query = $node["Prepare Query"].json.question;
const retrieval = $input.first().json;
const outputId = `out-${new Date().toISOString().slice(0, 10)}-answer-${Math.random().toString(36).slice(2, 8)}`;
const slug = query.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 48) || 'answer';
const answerRecord = {
  output_id: outputId,
  question: query,
  output_path: `outputs/${new Date().toISOString().slice(0, 10)}-${slug}.md`,
  evidence_used: retrieval.results.map((item) => item.path),
  should_review_for_feedback: true
};
return [{
  json: {
    status: 'needs_llm_node',
    question: query,
    retrieval,
    answer_record,
    llm_instructions: [
      'Insert your provider-specific AI node after this step.',
      'Read the retrieved wiki notes from retrieval.results[*].path.',
      'Generate the answer first.',
      'Then produce a canonical Feedback Record and send it to KB - Apply Feedback.'
    ],
    next_workflow: 'KB - Apply Feedback'
  }
}];
